runTest('dedupePredictionRows: repeated odds records collapse to one stable prediction row', () => {
  const rows = [
    {
      prediction_id: 'same',
      event: 'A @ B',
      market: 'home_away',
      side: 'home',
      selection: 'B',
      edge: -0.02,
      confidence_score: 50,
      odds_decimal: 1.8,
      odds_american: '-125',
    },
    {
      prediction_id: 'same',
      event: 'A @ B',
      market: 'home_away',
      side: 'home',
      selection: 'B',
      edge: -0.01,
      confidence_score: 50,
      odds_decimal: 1.9,
      odds_american: '-111',
    },
    {
      prediction_id: 'other',
      event: 'C @ D',
      market: 'home_away',
      side: 'away',
      selection: 'C',
      edge: -0.03,
      confidence_score: 60,
      odds_decimal: 2.1,
      odds_american: '+110',
    },
  ];

  const deduped = dedupePredictionRows(rows);
  assert.equal(deduped.length, 2);
  assert.equal(deduped[0].prediction_id, 'same');
  assert.equal(deduped[0].odds_american, '-111');
});

